#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,m,f[1<<20],s[N][25];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,a;i<=n;i++){
        scanf("%d",&a);
        for(int j=1;j<=m;j++)
            s[i][j]=s[i-1][j];
        s[i][a]++;
    }
    f[0]=0;
    for(int i=1;i<1<<m;i++){
        int len=0;
        for(int j=0;j<m;j++)
            if((i>>j)&1)
                len+=s[n][j+1];
        f[i]=1e9;
        for(int j=0;j<m;j++)
            if((i>>j)&1)
                f[i]=min(f[i],f[i-(1<<j)]+s[n][j+1]-(s[len][j+1]-s[len-s[n][j+1]][j+1]));
    }
    printf("%d",f[(1<<m)-1]);
    return 0;
}
